import React, { useState, useEffect, useContext, useRef } from 'react';
import { materialAPI } from '../services/api';
import { AuthContext } from '../context/AuthContext';

// Helper Icons
const getFileIcon = (type) => {
  const iconClass = "premium-resource-icon ";
  if (['pdf'].includes(type)) {
    return (
      <div className={iconClass + "icon-pdf"}>
        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" fill="currentColor" viewBox="0 0 16 16">
          <path fillRule="evenodd" d="M14 4.5V14a2 2 0 0 1-2 2h-1v-1h1a1 1 0 0 0 1-1V4.5h-2A1.5 1.5 0 0 1 9.5 3V1H4a1 1 0 0 0-1 1v9H2V2a2 2 0 0 1 2-2h5.5L14 4.5ZM1.6 11.85H0v3.999h.791v-1.342h.803c.287 0 .531-.057.732-.173.203-.117.358-.275.463-.474a1.42 1.42 0 0 0 .161-.677c0-.25-.053-.476-.158-.677a1.176 1.176 0 0 0-.46-.477c-.2-.12-.443-.179-.732-.179Zm.545 1.333a.795.795 0 0 1-.085.38.574.574 0 0 1-.238.241.794.794 0 0 1-.375.082H.788V12.48h.66c.218 0 .389.06.512.181.123.122.185.296.185.522Zm1.217-1.333v3.999h1.46c.401 0 .734-.08.998-.237a1.45 1.45 0 0 0 .595-.689c.13-.3.196-.662.196-1.084 0-.42-.065-.778-.196-1.075a1.426 1.426 0 0 0-.589-.68c-.264-.156-.599-.234-1.005-.234H3.362Zm.791.645h.563c.249 0 .45.05.603.151a.89.89 0 0 1 .354.454c.079.201.118.452.118.753a2.3 2.3 0 0 1-.068.592 1.14 1.14 0 0 1-.196.422.8.8 0 0 1-.334.252 1.298 1.298 0 0 1-.483.082h-.557v-2.706ZM7.46 11.85v2.66h-.845v-2.66h.845Zm-1.345 0v3.999h2.382v-.65H6.96v-1.05h1.106v-.654H6.96v-.99h1.27v-.655H6.115Z"/>
        </svg>
      </div>
    );
  }
  if (['doc', 'docx'].includes(type)) {
    return (
      <div className={iconClass + "icon-doc"}>
        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" fill="currentColor" viewBox="0 0 16 16">
          <path d="M4 0h5.293A1 1 0 0 1 10 .293L13.707 4a1 1 0 0 1 .293.707V14a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V2a2 2 0 0 1 2-2zm5.5 1.5v2a1 1 0 0 0 1 1h2l-3-3zM3 14a1 1 0 0 0 1 1h8a1 1 0 0 0 1-1V5.5H9a2 2 0 0 1-2-2V1H3v13z"/>
          <path d="M5 8h6v1H5zM5 10h6v1H5zM5 12h3v1H5z"/>
        </svg>
      </div>
    );
  }
  if (['jpg', 'jpeg', 'png', 'gif'].includes(type)) {
    return (
      <div className={iconClass + "icon-img"}>
        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" fill="currentColor" viewBox="0 0 16 16">
          <path d="M4.502 9a1.5 1.5 0 1 0 0-3 1.5 1.5 0 0 0 0 3z"/>
          <path d="M14.002 13a2 2 0 0 1-2 2h-10a2 2 0 0 1-2-2V5A2 2 0 0 1 2 3a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2v8a2 2 0 0 1-1.998 2zM14 2H4a1 1 0 0 0-1 1h9.002a2 2 0 0 1 2 2v7A1 1 0 0 0 15 11V3a1 1 0 0 0-1-1zM2.002 4a1 1 0 0 0-1 1v8l2.646-2.354a.5.5 0 0 1 .63-.062l2.66 1.773 3.71-3.71a.5.5 0 0 1 .577-.094l1.777 1.947V5a1 1 0 0 0-1-1h-10z"/>
        </svg>
      </div>
    );
  }
  return (
    <div className={iconClass + "icon-gen"}>
      <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" fill="currentColor" viewBox="0 0 16 16">
        <path d="M4 0h5.293A1 1 0 0 1 10 .293L13.707 4a1 1 0 0 1 .293.707V14a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V2a2 2 0 0 1 2-2zm5.5 1.5v2a1 1 0 0 0 1 1h2l-3-3zM3 14a1 1 0 0 0 1 1h8a1 1 0 0 0 1-1V5.5H9a2 2 0 0 1-2-2V1H3v13z"/>
      </svg>
    </div>
  );
};

const MaterialsUploadPage = () => {
  const { user } = useContext(AuthContext);
  const [materials, setMaterials] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [selectedSubject, setSelectedSubject] = useState('All');
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    subject: '',
    topic: '',
    file: null,
  });

  const fileInputRef = useRef(null);

  useEffect(() => {
    fetchMaterials();
  }, []);

  const fetchMaterials = async () => {
    setLoading(true);
    setError('');
    try {
      // Changed from getMyMaterials() to getAllMaterials()
      const res = await materialAPI.getAllMaterials();
      setMaterials(res.data.materials || []);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch materials');
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value, files } = e.target;
    setFormData((prev) => ({ ...prev, [name]: name === 'file' ? files[0] : value }));
  };

  const clearForm = () => {
    setFormData({ title: '', description: '', subject: '', topic: '', file: null });
    if(fileInputRef.current) fileInputRef.current.value = "";
  }

  const handleUploadMaterial = async (e) => {
    e.preventDefault();
    setError('');

    if (!formData.title || !formData.subject || !formData.file) {
      setError('Please complete the required fields before uploading.');
      return;
    }

    try {
      setLoading(true);
      const formDataToSend = new FormData();
      formDataToSend.append('title', formData.title);
      formDataToSend.append('description', formData.description);
      formDataToSend.append('subject', formData.subject);
      formDataToSend.append('topic', formData.topic);
      formDataToSend.append('file', formData.file);

      await materialAPI.uploadMaterial(formDataToSend);
      setSuccessMessage('Material uploaded successfully.');
      setTimeout(() => setSuccessMessage(''), 3000);
      clearForm();
      setShowForm(false);
      fetchMaterials();
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to upload material');
      setLoading(false);
    }
  };

  const handleDeleteMaterial = async (materialId) => {
    if (!window.confirm('Delete this material permanently?')) return;

    try {
      await materialAPI.deleteMaterial(materialId);
      setSuccessMessage('Material deleted successfully.');
      setTimeout(() => setSuccessMessage(''), 3000);
      fetchMaterials();
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to delete material');
    }
  };

  const subjects = ['All', ...new Set(materials.map((material) => material.subject))].slice(0, 10); // Limit to top subjects layout wise
  const filteredMaterials =
    selectedSubject === 'All'
      ? materials
      : materials.filter((material) => material.subject === selectedSubject);

  return (
    <div className="container-fluid py-4 min-vh-100 pb-5">
      <div className="container">
        <div className="portal-page-header">
          <span className="portal-page-kicker">Digital Library</span>
          <h1 className="portal-page-title">Resource Management</h1>
          <p className="portal-page-subtitle">
            Upload, organize, and explore the complete collection of study materials across the platform.
          </p>
        </div>

        {error && (
          <div className="alert alert-danger alert-dismissible fade show" role="alert">
            {error}
            <button type="button" className="btn-close" onClick={() => setError('')}></button>
          </div>
        )}

        {successMessage && (
          <div className="alert alert-success alert-dismissible fade show" role="alert">
            {successMessage}
            <button type="button" className="btn-close" onClick={() => setSuccessMessage('')}></button>
          </div>
        )}

        <div className="d-flex justify-content-between align-items-center mb-4 flex-wrap gap-3">
          <div className="premium-filter-bar flex-grow-1">
            {subjects.map((subject) => (
              <div
                key={subject}
                className={`premium-filter-chip ${selectedSubject === subject ? 'active' : ''}`}
                onClick={() => setSelectedSubject(subject)}
              >
                {subject}
              </div>
            ))}
          </div>
          <button 
            className="btn btn-primary rounded-pill px-4 shadow-sm fw-semibold d-flex align-items-center gap-2" 
            onClick={() => setShowForm(!showForm)}
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" viewBox="0 0 16 16">
              <path d="M.5 9.9a.5.5 0 0 1 .5.5v2.5a1 1 0 0 0 1 1h12a1 1 0 0 0 1-1v-2.5a.5.5 0 0 1 1 0v2.5a2 2 0 0 1-2 2H2a2 2 0 0 1-2-2v-2.5a.5.5 0 0 1 .5-.5z"/>
              <path d="M7.646 1.146a.5.5 0 0 1 .708 0l3 3a.5.5 0 0 1-.708.708L8.5 2.707V11.5a.5.5 0 0 1-1 0V2.707L5.354 4.854a.5.5 0 1 1-.708-.708l3-3z"/>
            </svg>
            {showForm ? 'Cancel Upload' : 'Upload Resource'}
          </button>
        </div>

        {showForm && (
          <div className="premium-panel mb-5">
            <div className="premium-panel-header">
              <h5 className="premium-panel-title">Upload New Resource</h5>
            </div>
            <div className="premium-panel-body">
              <form onSubmit={handleUploadMaterial}>
                <div className="row g-4">
                  <div className="col-lg-6">
                    <div className="mb-3">
                      <label htmlFor="title" className="form-label fw-medium text-muted small text-uppercase">Title *</label>
                      <input type="text" className="form-control" id="title" name="title" value={formData.title} onChange={handleInputChange} required placeholder="E.g., Intro to Algorithms" />
                    </div>
                    <div className="row">
                      <div className="col-md-6 mb-3">
                        <label htmlFor="subject" className="form-label fw-medium text-muted small text-uppercase">Subject *</label>
                        <input type="text" className="form-control" id="subject" name="subject" value={formData.subject} onChange={handleInputChange} required placeholder="E.g., Computer Science" />
                      </div>
                      <div className="col-md-6 mb-3">
                        <label htmlFor="topic" className="form-label fw-medium text-muted small text-uppercase">Topic</label>
                        <input type="text" className="form-control" id="topic" name="topic" value={formData.topic} onChange={handleInputChange} placeholder="E.g., Sorting" />
                      </div>
                    </div>
                    <div className="mb-3">
                      <label htmlFor="description" className="form-label fw-medium text-muted small text-uppercase">Description</label>
                      <textarea className="form-control" id="description" name="description" value={formData.description} onChange={handleInputChange} rows="3" placeholder="Brief context about this material..."></textarea>
                    </div>
                  </div>
                  <div className="col-lg-6 d-flex flex-column h-100">
                    <label htmlFor="file" className="form-label fw-medium text-muted small text-uppercase w-100">Select File *</label>
                    <label className="premium-upload-area flex-grow-1 d-flex flex-column align-items-center justify-content-center" htmlFor="file">
                       <div className="premium-upload-icon">
                         <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" fill="currentColor" viewBox="0 0 16 16">
                           <path d="M14 4.5V14a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V2a2 2 0 0 1 2-2h5.5L14 4.5zm-3 0A1.5 1.5 0 0 1 9.5 3V1H4a1 1 0 0 0-1 1v12a1 1 0 0 0 1 1h8a1 1 0 0 0 1-1V4.5h-2z"/>
                         </svg>
                       </div>
                       <div className="premium-upload-text">{formData.file ? formData.file.name : 'Click to Upload Asset'}</div>
                       <div className="premium-upload-hint">PDF, DOC, DOCX, PPT, PPTX or Image (Max 10MB)</div>
                    </label>
                    <input type="file" className="d-none" id="file" name="file" onChange={handleInputChange} accept=".pdf,.doc,.docx,.ppt,.pptx,.jpg,.jpeg,.png,.gif" required ref={fileInputRef} />
                  </div>
                </div>
                <div className="d-flex justify-content-end mt-4">
                  <button type="submit" className="btn btn-primary px-4 py-2 fw-semibold" disabled={loading}>
                    {loading ? 'Uploading...' : 'Publish Material'}
                  </button>
                </div>
              </form>
            </div>
          </div>
        )}

        {loading && materials.length === 0 ? (
          <div className="d-flex justify-content-center py-5 mt-5">
            <div className="spinner-border text-primary" role="status">
              <span className="visually-hidden">Loading...</span>
            </div>
          </div>
        ) : filteredMaterials.length === 0 ? (
          <div className="premium-panel p-5 text-center mt-4">
            <div className="portal-empty-state">No materials found for {selectedSubject !== 'All' ? selectedSubject : 'the platform'}.</div>
          </div>
        ) : (
          <div className="row g-4">
            {filteredMaterials.map((material) => {
               const isOwner = material.staffId?._id === user?._id;
               return (
                <div key={material._id} className="col-md-6 col-lg-4 col-xl-3 d-flex">
                  <div className="premium-resource-card w-100">
                    <div className="card-body p-4 d-flex flex-column">
                      {getFileIcon(material.fileType)}
                      <div className="badge bg-secondary mb-3 align-self-start">{material.subject}</div>
                      <h5 className="premium-resource-title">{material.title}</h5>
                      <p className="premium-resource-desc">{material.description || 'No description provided.'}</p>

                      <div className="text-muted small mb-2 d-flex align-items-center gap-2">
                         <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" fill="currentColor" viewBox="0 0 16 16"><path d="M11 6a3 3 0 1 1-6 0 3 3 0 0 1 6 0z"/><path fillRule="evenodd" d="M0 8a8 8 0 1 1 16 0A8 8 0 0 1 0 8zm8-7a7 7 0 0 0-5.468 11.37C3.242 11.226 4.805 10 8 10s4.757 1.225 5.468 2.37A7 7 0 0 0 8 1z"/></svg> 
                         {material.staffId?.name || 'Unknown Staff'}
                      </div>
                      <div className="text-muted small d-flex justify-content-between">
                         <span>{material.topic || 'General'}</span>
                         <span>{new Date(material.uploadedAt).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric'})}</span>
                      </div>
                    </div>
                    <div className="premium-resource-footer">
                      <a
                        href={`http://localhost:5000${material.fileUrl}`}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="btn btn-outline-primary flex-grow-1 btn-sm fw-semibold d-flex align-items-center justify-content-center gap-2"
                      >
                        <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" fill="currentColor" viewBox="0 0 16 16"><path d="M10.5 8a2.5 2.5 0 1 1-5 0 2.5 2.5 0 0 1 5 0z"/><path d="M0 8s3-5.5 8-5.5S16 8 16 8s-3 5.5-8 5.5S0 8 0 8zm8 3.5a3.5 3.5 0 1 0 0-7 3.5 3.5 0 0 0 0 7z"/></svg>
                        View
                      </a>
                      {isOwner && (
                        <button 
                          className="btn btn-outline-danger btn-sm" 
                          onClick={() => handleDeleteMaterial(material._id)}
                          title="Delete this material"
                        >
                          <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" fill="currentColor" viewBox="0 0 16 16">
                            <path d="M5.5 5.5A.5.5 0 0 1 6 6v6a.5.5 0 0 1-1 0V6a.5.5 0 0 1 .5-.5Zm2.5 0a.5.5 0 0 1 .5.5v6a.5.5 0 0 1-1 0V6a.5.5 0 0 1 .5-.5Zm3 .5a.5.5 0 0 0-1 0v6a.5.5 0 0 0 1 0V6Z"/>
                            <path d="M14.5 3a1 1 0 0 1-1 1H13v9a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V4h-.5a1 1 0 0 1-1-1V2a1 1 0 0 1 1-1H6a1 1 0 0 1 1-1h2a1 1 0 0 1 1 1h3.5a1 1 0 0 1 1 1v1ZM4.118 4 4 4.059V13a1 1 0 0 0 1 1h6a1 1 0 0 0 1-1V4.059L11.882 4H4.118ZM2.5 3h11V2h-11v1Z"/>
                          </svg>
                        </button>
                      )}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

export default MaterialsUploadPage;
